//! Bulk param tooltips — node-library coverage pass.
//!
//! Generated by a fan-out draft then voice-gated and reviewed. Same
//! `(type_id, param)` inventory channel as [`param_tooltips_table`]
//! (`crate::node_graph::param_doc`); kept in a separate file so the
//! hand-curated table stays small and this coverage pass is auditable in
//! one place. Voice rules identical: natural, no em-dashes or semicolons,
//! no AI-speak. See `feedback_product_copy_voice`.

// ─── Color & Tone ───

crate::param_tooltips!("node.brightness", {
    "weights" => "How much each of red, green, and blue counts toward the grey value. The defaults are the Rec.709 luma weights, which match how the eye sees brightness.",
});

crate::param_tooltips!("node.channel_mix", {
    "row0" => "How much red, green, blue, and alpha each feed into the new red channel. The default takes red straight through.",
    "row1" => "How much red, green, blue, and alpha each feed into the new green channel. The default takes green straight through.",
    "row2" => "How much red, green, blue, and alpha each feed into the new blue channel. The default takes blue straight through.",
    "row3" => "How much red, green, blue, and alpha each feed into the new alpha channel. The default takes alpha straight through.",
});

crate::param_tooltips!("node.color_lut", {
    "amount" => "Crossfades between the original image and the palette-mapped version. 0 leaves the source untouched and 1 is the full lookup.",
    "contrast" => "Pushes brightness around the midpoint before the lookup, which spreads the image across more of the palette. 1 leaves it unchanged, higher is punchier.",
});

crate::param_tooltips!("node.color_ramp", {
    "color_a" => "The colour mapped to the dark end of the image. Black areas pick up this colour.",
    "color_b" => "The colour mapped to the bright end of the image. White areas pick up this colour.",
});

crate::param_tooltips!("node.invert", {
    "intensity" => "How far to blend toward the inverted image, from 0 for the original up to 1 for the full negative. Values in between give a partial invert.",
});

crate::param_tooltips!("node.reinhard_tone_map", {
    "intensity" => "Brightens the image before the curve is applied, from 0 up to 16. 1 leaves it as is, higher pushes more of the picture toward the highlights.",
    "contrast" => "A second multiplier on the signal before tone mapping, from 0 to 8. 1 leaves it unchanged.",
    "curve" => "Which Reinhard curve to use. Extended keeps more detail in bright highlights, while Simple is the textbook version that crushes them harder.",
});

crate::param_tooltips!("node.saturation", {
    "saturation" => "How vivid the colours are. 0 is full greyscale, 1 leaves it unchanged, and above 1 oversaturates.",
});

crate::param_tooltips!("node.tone_map", {
    "exposure" => "Brightens or dims the image before the curve is applied. 1 leaves it unchanged, above 1 brightens, below 1 darkens.",
    "curve" => "How the bright highlights roll off. Narkowicz and Hill ACES are the filmic standards, AgX gives a more natural look, and Khronos PBR Neutral holds onto saturation in very bright colours.",
    "mode" => "What kind of display you are mapping to. SDR for a normal screen or export, PQ for HDR10 export, EDR for a macOS HDR display, and EDR Passthrough to skip the curve.",
    "paper_white" => "The brightness in nits that plain white should hit on an HDR display. Only used in the HDR output modes.",
    "max_nits" => "The peak brightness in nits your HDR display can reach, used to set where the brightest highlights land. Only used in the HDR output modes.",
});

