crate::param_tooltips!("node.color_sample", {
    "uv" => "Where in the image to read the colour, as a point from 0 to 1 across width and height. The centre is 0.5, 0.5.",
    "radius_px" => "Averages a square window of this many pixels around the sample point. 0 reads a single pixel, higher values smooth out noise so the reading reflects the region.",
});

crate::param_tooltips!("node.depth_estimate_midas", {
    "analysis_max_dim" => "The longest side, in pixels, the frame is shrunk to before the AI looks at it. Lower runs faster but reads depth coarsely, higher is sharper but slower.",
    "update_interval" => "How many frames to wait between depth estimates. 1 runs every frame for the freshest result, higher values ease the CPU load but the depth lags the picture a little.",
});

crate::param_tooltips!("node.optical_flow_estimate", {
    "analysis_max_dim" => "The longest side the image is shrunk to before flow is measured, in pixels. Smaller is faster and softer while larger catches finer motion at more cost.",
    "update_interval" => "How many frames between each flow measurement. Higher values save work but the motion lags further behind the picture.",
});

crate::param_tooltips!("node.track_persist", {
    "match_radius" => "How far a blob can move between frames and still count as the same one, in normalised canvas units. Raise it for fast movers, lower it for crowded scenes where IDs swap.",
    "grace_frames" => "How many frames to keep holding a blob after it drops out, measured in frames. Raise it to ride through flickery detections, lower it to clear stale blobs fast.",
});

// ─── Math & Convert ───

crate::param_tooltips!("node.array_connect_nearest", {
    "max_distance" => "How close two items must be before a line connects them, in the input's own coordinate space which is 0 to 1 for blob detections. Lower values only link items that are nearly touching.",
    "max_edges" => "Caps how many connecting lines can be drawn. Once this many edges exist the rest are skipped, which keeps a busy scene from filling with lines.",
});

crate::param_tooltips!("node.array_math", {
    "op" => "The operation run over every number in the list. Binary ops like Add, Multiply, Min and Mix read both inputs, while unary ops like Sine, Abs and Clamp01 read only the first.",
    "scale" => "The multiplier used by ScaleOffset and ShapePowClip, and the blend amount for Mix. Other operations ignore it.",
    "offset" => "Added after scaling in ScaleOffset. Only that operation reads it.",
    "exp" => "The power applied in ShapePowClip, where 1 is linear and higher bends the response into a steeper curve. Only that operation reads it.",
    "bias" => "Shifts the input before the power in ShapePowClip. Only that operation reads it.",
});

crate::param_tooltips!("node.fract_texture", {
    "scale" => "Multiplies the input before keeping only the fractional part, which sets how many times the gradient repeats. 10 gives ten tiled stripes from 0 to 1.",
});

crate::param_tooltips!("node.generate_range", {
    "start" => "The first number in the list.",
    "end" => "The last number in the list, or just short of it when End Inclusive is off.",
    "max_capacity" => "How many evenly spaced numbers to produce between the start and end.",
    "end_inclusive" => "Whether the last value lands exactly on the end. On is right for closed curves that loop back, off is right for spacing points evenly around a circle.",
});

crate::param_tooltips!("node.pack_channels", {
    "default_r" => "The value the red channel falls back to when nothing is wired into the red input.",
    "default_g" => "The value the green channel falls back to when nothing is wired into the green input.",
    "default_b" => "The value the blue channel falls back to when nothing is wired into the blue input.",
    "default_a" => "The value the alpha channel falls back to when nothing is wired into the alpha input. Defaults to 1 so the result stays fully opaque.",
});

crate::param_tooltips!("node.power_texture", {
    "exponent" => "Raises each value to this power. Above 1 pushes the midtones toward black for sharper points, and below 1 lifts the darks like a gamma brighten. Negative input is clamped to 0 first.",
});

crate::param_tooltips!("node.resolve_3d_accumulator", {
    "vol_res" => "Width and height of the volume in cells. This must match the particle scatter that filled the buffer.",
    "vol_depth" => "Depth of the volume in cells. This must match the particle scatter that filled the buffer.",
});

crate::param_tooltips!("node.resolve_accumulator", {
    "fixed_point_scale" => "The divisor that turns the raw counter values back into density. It must match the scale the scatter step wrote with, default 4096, or the brightness comes out wrong.",
});

crate::param_tooltips!("node.scalar_array_accumulator", {
    "increment" => "How much is added to every slot on each trigger. Use 90 to step every value by a quarter turn per hit, negative to count down.",
    "capacity" => "How many slots the running list holds. Set it to match the number of values the downstream node expects.",
    "initial" => "The starting values for the slots, taken from the first row of a table. Left unset, every slot starts at zero.",
});

crate::param_tooltips!("node.scale_offset_texture", {
    "scale" => "Multiplies every colour before the offset is added. 1 leaves it unchanged, and a negative value inverts. Use 2 with offset -1 to turn a 0 to 1 field back into a signed -1 to 1 one.",
    "offset" => "Added to every colour after the scale. 0 leaves it unchanged. Use 0.5 with scale 0.5 to fit a signed -1 to 1 field into the 0 to 1 range.",
});

crate::param_tooltips!("node.trig_texture", {
    "freq" => "Scales the input before the wave is applied, setting how many cycles fit across the range. The default of about 6.28 fits one full cycle across a 0 to 1 input.",
    "phase" => "Shifts the wave along, in degrees, so you can slide the ripples or animate them by sweeping this value.",
    "mode" => "Picks the wave shape from Sin, Cos, or Tan. Sin and Cos stay in the minus one to one range, Tan is clamped to keep the output stable.",
});

// ─── Fields & Coordinates ───

crate::param_tooltips!("node.block_displace_field", {
    "amount" => "How far blocks slide and how many of them move. At 0 nothing shifts, and as you raise it the displacement grows from sparse to dense.",
    "block_size" => "The size of each block in pixels. Smaller blocks give a fine grain and larger blocks give chunky datamosh tearing.",
    "speed" => "How fast the random pattern reshuffles over time. Higher values churn the blocks more often.",
});

crate::param_tooltips!("node.centered_uv", {
    "cx" => "Horizontal point the coordinates measure from, where 0.5 is the middle of the canvas. Move it to slide a radial or zoom effect off centre.",
    "cy" => "Vertical point the coordinates measure from, where 0.5 is the middle of the canvas.",
    "scale_x" => "Stretches the horizontal coordinates. 1 leaves them as is, higher spreads the pattern wider, and a negative value flips it left to right.",
    "scale_y" => "Stretches the vertical coordinates. 1 leaves them as is, and a negative value flips it top to bottom.",
});

crate::param_tooltips!("node.field_combine", {
    "a" => "How much of the input's red channel feeds the output value. At 1 the red passes through, 0 ignores it, negative flips its sign.",
    "b" => "How much of the input's green channel feeds the output value. At 0 the green is ignored, higher mixes more of it in.",
    "c" => "A constant added to the result, useful for shifting the whole field up or down to centre it where you want.",
});

crate::param_tooltips!("node.gradient_central_diff", {
    "channel" => "Which colour channel the slope is measured from, R, G, B, or A. Use R for a greyscale height field.",
    "scale_mode" => "How the slope is scaled. Texel measures the raw pixel-to-pixel difference and suits normal maps and heightfields. UV scales by the image size so the result is in per-UV-unit space, which fluid-sim flow needs.",
    "wrap_mode" => "How edge pixels read their neighbours. Clamp holds the edge for normal images. Repeat wraps around to the far side, which you want for a tiling or cyclic fluid field.",
});

crate::param_tooltips!("node.gradient_central_diff_3d", {
    "vol_res" => "The width and height of the volume in voxels, from 16 to 512. Match it to the density volume you are feeding in.",
    "vol_depth" => "How many slices deep the volume is, from 16 to 512. Match it to the density volume you are feeding in.",
});

crate::param_tooltips!("node.grid_uv_field", {
    "grid_size" => "How many sample points across and down, so the total is this number squared. Changing it rebuilds the chain since it sets the buffer size.",
});

crate::param_tooltips!("node.hash_field_by_seed", {
    "seed" => "Picks which random layout you get. The same seed always gives the same result, so wire a beat or trigger here to reshuffle the pattern on cue.",
    "seed_x" => "How strongly the seed shifts the field along its first axis before hashing. Changing it gives a different family of random offsets.",
    "seed_y" => "How strongly the seed shifts the field along its second axis before hashing. Changing it gives a different family of random offsets.",
    "mode" => "Hash2 returns a random pair in the red and green channels, good for 2D offsets. Hash1 returns a single random value across red, green, and blue.",
});

crate::param_tooltips!("node.lic_integrate", {
    "steps" => "How many samples to walk along the flow in each direction. More steps draw longer smears, up to a limit of 64.",
    "dt" => "How far each step travels, in pixels. Steps times this sets the total streak length.",
});

crate::param_tooltips!("node.neighbor_smooth", {
    "grid_size" => "The width of the square grid the points are laid out on. This has to match the producer feeding it, since that is how each point finds its four neighbours.",
    "center_weight" => "How much each point keeps its own value versus averaging in its neighbours. 1 leaves it untouched and lower values smooth harder, with 0.2 being heavy smoothing.",
});

crate::param_tooltips!("node.polar_field", {
    "cx" => "The horizontal centre that angle and distance are measured from, where 0.5 is the middle of the frame.",
    "cy" => "The vertical centre that angle and distance are measured from, where 0.5 is the middle of the frame.",
});

crate::param_tooltips!("node.rotate_2d", {
    "angle" => "How far to spin the coordinate field around the centre, in degrees. A positive angle turns the +X direction toward +Y. This rotates the coordinates used for a warp, not the picture itself.",
});

crate::param_tooltips!("node.rotate_vec2_by_angle", {
    "angle" => "Turns every vector in the field by this amount, in degrees. The default 90 gives the perpendicular curl flow used for fluid sims.",
});

crate::param_tooltips!("node.sample_volume_2d", {
    "slice_z" => "How deep into the volume to cut the slice, from the front at 0 to the back at 1. Sweep it smoothly to animate through the volume.",
    "uv_scale" => "Zooms the slice into the output frame. 1 fills it normally, higher crops in tighter, lower pulls back.",
    "center_x" => "Shifts which part of the slice you see along X, from -1 to 1. Use it to pan across the volume when zoomed in.",
    "center_y" => "Shifts which part of the slice you see along Y, from -1 to 1. Use it to pan across the volume when zoomed in.",
});

crate::param_tooltips!("node.scanline_jitter_field", {
    "amount" => "How far the torn rows slide sideways and how many of them tear, from 0 for none up to 1. Feed the output into a Remap in Relative mode.",
    "scanline" => "How many rows tear at once, from 0 for a clean image up to 1 for heavy tearing across the frame.",
    "speed" => "How fast the tearing pattern reshuffles over time, from 0.1 for a slow drift up to 10 for a fast jitter.",
});

crate::param_tooltips!("node.sin_term", {
    "a" => "How much the field's red channel feeds the wave, usually the X coordinate. Set a and b together to aim the wave along X, Y, or a diagonal.",
    "b" => "How much the field's green channel feeds the wave, usually the Y coordinate. Leave it at 0 to read only the red channel from a scalar field.",
    "c" => "A constant added to the projection before the wave, which shifts its phase.",
    "freq" => "The base frequency of the wave, so higher values pack more cycles into the same space. Wire one shared value into every term to keep them in phase.",
    "freq_scale" => "A per-term multiplier on the base frequency. Give each term a different scale to layer waves at related rates.",
    "time" => "The base time that moves the wave along. Wire the generator time in so every term advances together.",
    "time_scale" => "A per-term multiplier on time, which sets how fast this wave drifts. Negative values send it the other way.",
});

crate::param_tooltips!("node.slope_displace", {
    "strength" => "How much the embossed base layer drives the displacement. Higher pushes pixels further along the contrast contours for a more liquid pull.",
    "step" => "How far apart the gradient is sampled, in pixels. Larger reads a broader slope for a softer, wider warp.",
    "weight" => "Scales the final pixel shift, measured in UV units. The default is tiny on purpose since even small values move pixels noticeably.",
});

crate::param_tooltips!("node.texture_advect", {
    "dt" => "How far the flow drags the image each frame, in pixels, default 1. Negative runs the flow backwards for trail-erase tricks. Wire it to an LFO to pulse the motion.",
    "boundary" => "What happens at the edges, Repeat for looping fluid sims or Clamp to fade off-frame samples into the edge colour.",
});

crate::param_tooltips!("node.uv_displace_by_flow", {
    "weight" => "How far the flow field pushes the image, default 0.001 which is about one pixel at 1080p. Higher smears it more, negative pushes the other way.",
    "bias" => "The neutral midpoint of the flow channels, default 0.5 for standard 0 to 1 flow. Set it to 0 when the flow data is already signed around zero.",
});
